<?php
 namespace League\CommonMark\Inline\Renderer; use League\CommonMark\ElementRendererInterface; use League\CommonMark\HtmlElement; use League\CommonMark\Inline\Element\AbstractInline; use League\CommonMark\Inline\Element\Emphasis; final class EmphasisRenderer implements InlineRendererInterface { public function render(AbstractInline $inline, ElementRendererInterface $htmlRenderer) { if (!($inline instanceof Emphasis)) { throw new \InvalidArgumentException('Incompatible inline type: ' . \get_class($inline)); } $attrs = $inline->getData('attributes', []); return new HtmlElement('em', $attrs, $htmlRenderer->renderInlines($inline->children())); } } 